function problem=makeRectangularTimingProblem(mode,eventTime,fixedEvent, ...
        returnTime,returnFixed,configuration)
%MAKERECTANGULARTIMINGPROBLEM Construct an analytic schedule problem.
if nargin<2,eventTime=.4;end
if nargin<3,fixedEvent=false;end
if nargin<4,returnTime=1;end
if nargin<5,returnFixed=false;end
if nargin<6,configuration=struct();end
schedule=lmz.schedule.EventSchedule.fromCyclic({'impact'},eventTime, ...
    returnTime,'FixedMask',logical(fixedEvent), ...
    'ReturnTimeFixed',logical(returnFixed),'MinimumGap',1e-8, ...
    'StartSectionId','apex','StopSectionId','apex');
configuration.EventSchedule=schedule;
problem=lmz.schedule.SectionReturnTimingProblem( ...
    lmzmodels.tutorial_hopper.Model(),'section_return_timing', ...
    lmztest.RectangularTimingProvider(mode),[0;0;1;0],9.81, ...
    schedule,configuration);
end
